{
  "title": "أعمار الهياكل",
  "group": "الأعمار",
  "options": [
    {
      "text": "يتم التجميع بنجاح",
      "hint": "الهياكل التي تحتوي على مراجع تحتاج إلى تعليقات العمر"
    },
    {
      "text": "خطأ: محدد العمر مفقود"
    },
    {
      "text": "خطأ: عدم تطابق العمر",
      "hint": "لم نحدد أي أعمار بعد"
    },
    {
      "text": "خطأ: مرجع غير صالح",
      "hint": "المراجع صالحة، ولكن هناك شيء آخر مفقود"
    }
  ],
  "objectives": [
    "فهم تعليقات العمر في تعريفات الهياكل",
    "تحديد متى تتطلب حقول الهيكل معاملات العمر",
    "تطبيق تعليقات العمر بشكل صحيح في تطبيقات الهيكل"
  ],
  "questionProse": [
    "هل سيتم تجميع تعريف الهيكل هذا؟ لماذا أو لماذا لا؟"
  ],
  "hintsProse": [],
  "explanationProse": [
    "يفشل الكود لأن الهياكل التي تحتوي على مراجع يجب أن تحدد الأعمار. إليك كيفية إصلاحه:",
    "الأنماط الشائعة:",
    "أفضل الممارسات:\n      1. استخدم الأنواع المملوكة (String) عندما تحتاج إلى تخزين البيانات إلى أجل غير مسمى\n      2. استخدم المراجع عندما يكون عمر الهيكل أقصر بوضوح من عمر البيانات\n      3. فكر في معاملات عمر متعددة عندما يمكن أن يكون للمراجع أعمار مختلفة\n      4. وثق علاقات العمر في الهياكل المعقدة"
  ]
}
